SELECT 
FROM t_travel_post p


        AND (p.title LIKE CONCAT('%', #{keyword}, '%')
        OR p.summary LIKE CONCAT('%', #{keyword}, '%'))


        AND p.destination_id = #{destination_id}


        AND p.status = #{status}


        AND p.id IN (SELECT post_id FROM t_post_tag WHERE tag_id = #{tag_id})


ORDER BY p.created_at DESC
LIMIT #{offset}, #{size}

